from web3 import Web3
import json

class Web3Auth:
    def __init__(self, private_key):
        self.private_key = private_key
        self.w3 = Web3(Web3.HTTPProvider('https://mainnet.infura.io/v3/YOUR_PROJECT_ID'))

    def verify_signature(self, signed_message):
        try:
            address = self.w3.eth.account.recover(signed_message['signature'], message=signed_message['message'])
            return address
        except Exception as e:
            print(f'Error: {str(e)}')
            return None

def main():
    private_key = 'YOUR_PRIVATE_KEY'
    web3_auth = Web3Auth(private_key)
    
    signed_message = json.loads(input('Enter signed message in JSON format (e.g. {"signature": "0x123456789...", "message": "Hello, World!"}): '))
    address = web3_auth.verify_signature(signed_message)

    if address is not None:
        print(f'Authenticated user address: {address}')
    else:
        print('Authentication failed.')

if __name__ == '__main__':
    main()